class Solution:
    def findLUSlength(self, strs):
        """
        :type strs: List[str]
        :rtype: int
        """
        def is_subsequence(s, t):
            # Check if s is subsequence of t
            it = iter(t)
            return all(c in it for c in s)

        # Sort by length descending, then lexicographically
        strs.sort(key=lambda x: (-len(x), x))

        for i, s in enumerate(strs):
            # Check if s is not subsequence of any other string
            is_uncommon = True
            for j, t in enumerate(strs):
                if i != j and is_subsequence(s, t):
                    is_uncommon = False
                    break

            if is_uncommon:
                return len(s)

        return -1
